#include <stdio.h>
#include <stdint.h>

uint64_t power_uint64(uint64_t base, uint64_t exp){
    uint64_t result = 1;
    while(exp){
        if(exp & 1ULL) result *= base;
        base *= base;
        exp >>= 1ULL;
    }
    return result;
}

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    for(int tc=0; tc<T; ++tc){
        unsigned long long p, x;
        if(scanf("%llu %llu", &p, &x)!=2) break;
        printf("%llu\n", power_uint64(x, p));
    }
    return 0;
}

