import sys
from functools import partial

def create_power_func(power):
    # partial fixes the exponent argument of the lambda (base, exp)
    return partial(lambda base, exp: base ** exp, exp=power)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        p = int(next(it))
        x = int(next(it))
        power_func = create_power_func(p)
        out_lines.append(str(power_func(x)))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

